const root = items[0].json;
const body = root.body !== undefined ? root.body : root;
const source = String(body.source || 'session');
const raw_summary = typeof body.raw_summary === 'string' ? body.raw_summary : JSON.stringify(body.raw_summary ?? body.summary ?? '');
const projects_touched = Array.isArray(body.projects_touched) ? body.projects_touched : [];
const new_concepts = Array.isArray(body.new_concepts) ? body.new_concepts : [];
const decisions_made = Array.isArray(body.decisions_made) ? body.decisions_made : [];
const open_questions = Array.isArray(body.open_questions) ? body.open_questions : [];
return [{ json: { source, raw_summary, projects_touched, new_concepts, decisions_made, open_questions } }];
